JSON:
{
  "title": "AITA for telling my wife forget it and going out by myself for my birthday instead of going to her fancy dinner reservation",
  "subreddit": "r/AmItheAsshole",
  "author": "u/throwaway",
  "verdict": "NTA",
  "nodes": [
    {
      "id": 1,
      "text": "Guy just wants a chill, low-key chain restaurant dinner for his birthday.",
      "type": "context",
      "parent": null
    },
    {
      "id": 2,
      "text": "Wife has OCD and needs every detail planned in advance.",
      "type": "context",
      "parent": 1
    },
    {
      "id": 3,
      "text": "He repeatedly tells her: no reservations, no fancy plans, just vibes.",
      "type": "action",
      "parent": 2
    },
    {
      "id": 4,
      "text": "Wife keeps pressing for exact times, places, and reservation details.",
      "type": "escalation",
      "parent": 3
    },
    {
      "id": 5,
      "text": "Birthday arrives. He gets home ready for Olive Garden breadsticks.",
      "type": "context",
      "parent": 4
    },
    {
      "id": 6,
      "text": "Wife is dressed up — she booked a fancy sushi place as a surprise.",
      "type": "conflict",
      "parent": 5
    },
    {
      "id": 7,
      "text": "He tells her this is the opposite of what he asked for.",
      "type": "reaction",
      "parent": 6
    },
    {
      "id": 8,
      "text": "She argues she put real effort into planning the surprise.",
      "type": "reaction",
      "parent": 6
    },
    {
      "id": 9,
      "text": "He says forget it and leaves to eat at Olive Garden alone.",
      "type": "action",
      "parent": 7
    },
    {
      "id": 10,
      "text": "They argue again when he gets home.",
      "type": "escalation",
      "parent": 9
    },
    {
      "id": 11,
      "text": "Reddit rules NTA — he clearly stated what he wanted repeatedly.",
      "type": "verdict",
      "parent": 10
    }
  ]
}
